-- {"operators": "INNER_JOIN,AGGREGATE,HAVING,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER,ORDER_LINE", "ducklake": true}
WITH high_value AS (SELECT OL_W_ID, OL_O_ID, OL_D_ID FROM dl.ORDER_LINE GROUP BY OL_W_ID, OL_O_ID, OL_D_ID HAVING SUM(OL_AMOUNT) > (SELECT AVG(OL_AMOUNT) * 5 FROM dl.ORDER_LINE)) SELECT hv.OL_W_ID, hv.OL_D_ID, hv.OL_O_ID, c.C_LAST FROM high_value hv JOIN dl.OORDER o ON hv.OL_W_ID = o.O_W_ID AND hv.OL_D_ID = o.O_D_ID AND hv.OL_O_ID = o.O_ID JOIN dl.CUSTOMER c ON o.O_W_ID = c.C_W_ID AND o.O_D_ID = c.C_D_ID AND o.O_C_ID = c.C_ID;
